CREATE TYPE "CashFlowCategory" AS ENUM ('OPERATING','INVESTING','FINANCING','NON_CASH');
CREATE TYPE "ManagementPackStatus" AS ENUM ('DRAFT','PENDING_APPROVAL','APPROVED','PUBLISHED');
CREATE TYPE "YearEndRolloverStatus" AS ENUM ('DRAFT','PENDING_APPROVAL','COMPLETED');
ALTER TABLE "ledger_accounts" ADD COLUMN "cashFlowCategory" "CashFlowCategory";
CREATE TABLE "finance_auditor_grants" ("id" TEXT NOT NULL,"employeeId" TEXT NOT NULL,"expiresAt" TIMESTAMP(3),"isActive" BOOLEAN NOT NULL DEFAULT true,"grantedById" TEXT NOT NULL,"grantedAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"revokedById" TEXT,"revokedAt" TIMESTAMP(3),CONSTRAINT "finance_auditor_grants_pkey" PRIMARY KEY("id")); CREATE UNIQUE INDEX "finance_auditor_grants_employeeId_key" ON "finance_auditor_grants"("employeeId"); CREATE INDEX "finance_auditor_grants_isActive_expiresAt_idx" ON "finance_auditor_grants"("isActive","expiresAt");
CREATE TABLE "management_report_packs" ("id" TEXT NOT NULL,"packNumber" TEXT NOT NULL,"title" TEXT NOT NULL,"periodFrom" TIMESTAMP(3) NOT NULL,"periodTo" TIMESTAMP(3) NOT NULL,"status" "ManagementPackStatus" NOT NULL DEFAULT 'DRAFT',"snapshot" JSONB NOT NULL,"createdById" TEXT NOT NULL,"submittedById" TEXT,"submittedAt" TIMESTAMP(3),"approvedById" TEXT,"approvedAt" TIMESTAMP(3),"publishedAt" TIMESTAMP(3),"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL,CONSTRAINT "management_report_packs_pkey" PRIMARY KEY("id")); CREATE UNIQUE INDEX "management_report_packs_packNumber_key" ON "management_report_packs"("packNumber"); CREATE INDEX "management_report_packs_status_periodTo_idx" ON "management_report_packs"("status","periodTo");
CREATE TABLE "year_end_rollovers" ("id" TEXT NOT NULL,"sourceFiscalYearId" TEXT NOT NULL,"targetFiscalYearId" TEXT NOT NULL,"status" "YearEndRolloverStatus" NOT NULL DEFAULT 'DRAFT',"retainedEarningsAccountId" TEXT NOT NULL,"snapshot" JSONB NOT NULL,"createdById" TEXT NOT NULL,"submittedById" TEXT,"submittedAt" TIMESTAMP(3),"approvedById" TEXT,"approvedAt" TIMESTAMP(3),"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL,CONSTRAINT "year_end_rollovers_pkey" PRIMARY KEY("id")); CREATE UNIQUE INDEX "year_end_rollovers_sourceFiscalYearId_key" ON "year_end_rollovers"("sourceFiscalYearId"); CREATE INDEX "year_end_rollovers_status_idx" ON "year_end_rollovers"("status");
CREATE TABLE "account_opening_balances" ("id" TEXT NOT NULL,"rolloverId" TEXT NOT NULL,"fiscalYearId" TEXT NOT NULL,"accountId" TEXT NOT NULL,"debit" DECIMAL(18,2) NOT NULL DEFAULT 0,"credit" DECIMAL(18,2) NOT NULL DEFAULT 0,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,CONSTRAINT "account_opening_balances_pkey" PRIMARY KEY("id")); CREATE UNIQUE INDEX "account_opening_balances_fiscalYearId_accountId_key" ON "account_opening_balances"("fiscalYearId","accountId"); CREATE INDEX "account_opening_balances_rolloverId_idx" ON "account_opening_balances"("rolloverId"); ALTER TABLE "account_opening_balances" ADD CONSTRAINT "account_opening_balances_rolloverId_fkey" FOREIGN KEY("rolloverId") REFERENCES "year_end_rollovers"("id") ON DELETE CASCADE ON UPDATE CASCADE;
